import software.amazon.awssdk.auth.credentials.{AwsBasicCredentials, AwsCredentialsProvider, DefaultCredentialsProvider}
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model.{S3Exception, PutObjectRequest, PutObjectResponse}
import software.amazon.awssdk.services.secretsmanager.SecretsManagerClient
import software.amazon.awssdk.services.secretsmanager.model.{GetSecretValueRequest, GetSecretValueResponse}
import scala.util.{Try, Success, Failure}

trait AwsCredentialsService {
  def getCredentials: AwsCredentialsProvider
}

class EnvironmentCredentialsService extends AwsCredentialsService {
  override def getCredentials: AwsCredentialsProvider = DefaultCredentialsProvider.create()
}

class SecretManagerCredentialsService(secretName: String, region: Region) extends AwsCredentialsService {
  private val secretsClient = SecretsManagerClient.builder().region(region).build()
  
  override def getCredentials: AwsCredentialsProvider = {
    val request = GetSecretValueRequest.builder().secretId(secretName).build()
    val response: GetSecretValueResponse = secretsClient.getSecretValue(request)
    
    val secret = response.secretString()
    val credentials = parseCredentials(secret)
    
    new AwsCredentialsProvider {
      override def resolveCredentials(): AwsBasicCredentials = 
        AwsBasicCredentials.create(credentials("accessKey"), credentials("secretKey"))
    }
  }
  
  private def parseCredentials(secret: String): Map[String, String] = {
    val keyValuePairs = secret.split("\\s+").map(_.split("=")).filter(_.length == 2)
    keyValuePairs.map(pair => pair(0) -> pair(1)).toMap
  }
}

trait AwsService {
  def execute[T](operation: => T): Try[T]
}

class SecureAwsService(credentialsService: AwsCredentialsService, region: Region) extends AwsService {
  private val s3Client = S3Client.builder()
    .region(region)
    .credentialsProvider(credentialsService.getCredentials)
    .build()
  
  override def execute[T](operation: => T): Try[T] = {
    Try(operation) recover {
      case e: S3Exception => throw new RuntimeException(s"AWS S3 Error: ${e.getMessage}", e)
      case e: Exception => throw new RuntimeException(s"Unexpected error: ${e.getMessage}", e)
    }
  }
  
  def uploadToS3(bucketName: String, key: String, content: String): Try[PutObjectResponse] = {
    execute {
      val request = PutObjectRequest.builder()
        .bucket(bucketName)
        .key(key)
        .build()
      
      s3Client.putObject(request, content)
    }
  }
}

object AwsIntegrationService {
